#!/usr/bin/env node
/**
 * Bundles Piskel's source files into a single JS file and CSS file,
 * replacing Grunt's concat task. Reads the file order from piskel-script-list.js.
 */
import { readFileSync, writeFileSync, mkdirSync, readdirSync, statSync } from 'fs';
import { join, dirname, resolve } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const piskelSrc = resolve(__dirname, '../src/editor/piskel');
const outDir = resolve(__dirname, '../public/piskel');

mkdirSync(outDir, { recursive: true });

// --- Bundle JS ---
// Read script list (it uses exports or pskl_exports pattern)
const scriptListCode = readFileSync(join(piskelSrc, 'piskel-script-list.js'), 'utf8');
// Extract the array by evaluating with a shim
const pskl_exports = {};
const exports_shim = pskl_exports;
const fn = new Function('exports', 'pskl_exports', scriptListCode);
fn(exports_shim, pskl_exports);
const scriptPaths = pskl_exports.scripts;

// Include everything except devtools — jQuery 1.8 + jQuery UI are bundled from Piskel's own copies
const skipFiles = new Set([]);

// Devtools are not needed for the embedded editor
const skipPrefixes = ['js/devtools/'];

let jsBundle = '// Piskel bundle - auto-generated by bundle-piskel.js\n';
jsBundle += '// Do not edit directly, modify source files in src/piskel/js/\n\n';

let included = 0;
let skipped = 0;

for (const scriptPath of scriptPaths) {
    if (skipFiles.has(scriptPath)) {
        skipped++;
        continue;
    }
    if (skipPrefixes.some(p => scriptPath.startsWith(p))) {
        skipped++;
        continue;
    }

    const fullPath = join(piskelSrc, scriptPath);
    try {
        const content = readFileSync(fullPath, 'utf8');
        jsBundle += `// --- ${scriptPath} ---\n`;
        jsBundle += content;
        jsBundle += ';\n\n';
        included++;
    } catch (e) {
        console.warn(`Warning: could not read ${fullPath}: ${e.message}`);
    }
}

writeFileSync(join(outDir, 'piskel.js'), jsBundle);
console.log(`JS: bundled ${included} files, skipped ${skipped} -> public/piskel/piskel.js`);

// --- Bundle CSS ---
const styleListCode = readFileSync(join(piskelSrc, 'piskel-style-list.js'), 'utf8');
const style_exports = {};
const fn2 = new Function('exports', 'pskl_exports', styleListCode);
fn2(style_exports, style_exports);
const stylePaths = style_exports.styles;

let cssBundle = '/* Piskel styles - auto-generated */\n\n';
let cssIncluded = 0;

if (stylePaths) {
    for (const stylePath of stylePaths) {
        const fullPath = join(piskelSrc, stylePath);
        try {
            const content = readFileSync(fullPath, 'utf8');
            cssBundle += `/* --- ${stylePath} --- */\n`;
            cssBundle += content;
            cssBundle += '\n\n';
            cssIncluded++;
        } catch (e) {
            console.warn(`Warning: could not read ${fullPath}: ${e.message}`);
        }
    }
} else {
    // Fallback: just concat all CSS files
    function collectCss(dir) {
        for (const entry of readdirSync(dir)) {
            const full = join(dir, entry);
            if (statSync(full).isDirectory()) {
                collectCss(full);
            } else if (entry.endsWith('.css')) {
                cssBundle += `/* --- ${full.replace(piskelSrc + '/', '')} --- */\n`;
                cssBundle += readFileSync(full, 'utf8');
                cssBundle += '\n\n';
                cssIncluded++;
            }
        }
    }
    collectCss(join(piskelSrc, 'css'));
}

writeFileSync(join(outDir, 'piskel.css'), cssBundle);
console.log(`CSS: bundled ${cssIncluded} files -> public/piskel/piskel.css`);

// --- Copy fonts ---
const fontSrc = join(piskelSrc, 'css/fonts');
const fontDest = join(outDir, 'fonts');
try {
    mkdirSync(fontDest, { recursive: true });
    for (const entry of readdirSync(fontSrc)) {
        writeFileSync(join(fontDest, entry), readFileSync(join(fontSrc, entry)));
    }
    console.log('Fonts: copied to public/piskel/fonts/');
} catch (e) {
    console.warn('Warning: could not copy fonts:', e.message);
}

// --- Build HTML templates ---
// Read the main index.html and resolve @@include directives
const indexHtml = readFileSync(join(piskelSrc, 'piskel-index.html'), 'utf8');

function resolveIncludes(html, baseDir) {
    return html.replace(/@@include\('([^']+)'(?:,\s*\{[^}]*\})?\)/g, (match, templatePath) => {
        const fullPath = join(baseDir, templatePath);
        try {
            const content = readFileSync(fullPath, 'utf8');
            return resolveIncludes(content, dirname(fullPath));
        } catch (e) {
            console.warn(`Warning: template not found: ${fullPath}`);
            return `<!-- missing: ${templatePath} -->`;
        }
    });
}

const resolvedHtml = resolveIncludes(indexHtml, piskelSrc);

// Extract just the body content between body-main-start and body-main-end
const bodyMatch = resolvedHtml.match(/<!--body-main-start-->([\s\S]*?)<!--body-main-end-->/);
const bodyContent = bodyMatch ? bodyMatch[1] : resolvedHtml;

writeFileSync(join(outDir, 'piskel-body.html'), bodyContent.trim());
console.log(`HTML: resolved templates -> public/piskel/piskel-body.html`);

// Copy image assets
const imgSrc = join(piskelSrc, 'img');
const imgDest = join(outDir, 'img');
try {
    mkdirSync(imgDest, { recursive: true });
    function copyDir(src, dest) {
        mkdirSync(dest, { recursive: true });
        for (const entry of readdirSync(src)) {
            const srcPath = join(src, entry);
            const destPath = join(dest, entry);
            if (statSync(srcPath).isDirectory()) {
                copyDir(srcPath, destPath);
            } else {
                writeFileSync(destPath, readFileSync(srcPath));
            }
        }
    }
    copyDir(imgSrc, imgDest);
    console.log('Images: copied to public/piskel/img/');
} catch (e) {
    console.warn('Warning: could not copy images:', e.message);
}

// --- Generate icons CSS from individual PNGs (replaces Grunt sprite task) ---
const iconCategories = ['tools', 'transform', 'settings', 'frame', 'common', 'minimap'];
let iconsCss = '/* Auto-generated icon CSS */\n\n';
for (const cat of iconCategories) {
    const catDir = join(piskelSrc, 'img/icons', cat);
    let files;
    try { files = readdirSync(catDir); } catch { continue; }
    for (const file of files.sort()) {
        if (!file.endsWith('.png') || file.includes('@2x')) continue;
        const name = file.replace('.png', '');
        iconsCss += `.icon-${name} {\n`;
        iconsCss += `  background-image: url('/piskel/img/icons/${cat}/${file}');\n`;
        iconsCss += `  background-repeat: no-repeat;\n`;
        iconsCss += `  background-position: center;\n`;
        iconsCss += `  background-size: 36px 36px;\n`;
        iconsCss += `}\n\n`;
    }
}
writeFileSync(join(outDir, 'icons.css'), iconsCss);
console.log('Icons CSS: generated -> public/piskel/icons.css');

console.log('Done!');
